# Server Actions

Server Actions are async functions that execute on the server. They are the idiomatic way to handle data mutations in Next.js App Router applications.

## Defining Server Actions

### In a Separate File (Recommended)

```tsx
// app/actions.ts
'use server'

import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string
  const content = formData.get('content') as string

  await db.post.create({ data: { title, content } })

  revalidatePath('/blog')
  redirect('/blog')
}

export async function deletePost(id: string) {
  await db.post.delete({ where: { id } })
  revalidatePath('/blog')
}
```

### Inline in a Server Component

```tsx
// app/blog/page.tsx (Server Component)
export default function BlogPage() {
  async function createPost(formData: FormData) {
    'use server'
    const title = formData.get('title') as string
    await db.post.create({ data: { title } })
    revalidatePath('/blog')
  }

  return (
    <form action={createPost}>
      <input name="title" required />
      <button type="submit">Create</button>
    </form>
  )
}
```

## Using with Forms

### Basic Form

```tsx
// app/contact/page.tsx
import { submitContact } from './actions'

export default function ContactPage() {
  return (
    <form action={submitContact}>
      <input name="email" type="email" required />
      <textarea name="message" required />
      <button type="submit">Send</button>
    </form>
  )
}
```

Forms with Server Actions work without JavaScript (progressive enhancement). When JS is available, the form submits without a full page reload.

### With useActionState (Validation & Pending)

```tsx
// app/signup/actions.ts
'use server'

export async function signup(
  prevState: { error?: string } | undefined,
  formData: FormData
) {
  const email = formData.get('email') as string
  const password = formData.get('password') as string

  if (password.length < 8) {
    return { error: 'Password must be at least 8 characters' }
  }

  try {
    await createUser({ email, password })
  } catch (e) {
    return { error: 'Email already exists' }
  }

  redirect('/dashboard')
}
```

```tsx
// app/signup/form.tsx
'use client'

import { useActionState } from 'react'
import { signup } from './actions'

export default function SignupForm() {
  const [state, action, pending] = useActionState(signup, undefined)

  return (
    <form action={action}>
      <input name="email" type="email" required />
      <input name="password" type="password" required />
      {state?.error && <p className="text-red-500">{state.error}</p>}
      <button type="submit" disabled={pending}>
        {pending ? 'Creating account...' : 'Sign up'}
      </button>
    </form>
  )
}
```

### With useFormStatus (Submit Button)

```tsx
'use client'

import { useFormStatus } from 'react-dom'

export function SubmitButton({ label = 'Submit' }: { label?: string }) {
  const { pending } = useFormStatus()
  return (
    <button type="submit" disabled={pending}>
      {pending ? 'Submitting...' : label}
    </button>
  )
}
```

## Calling Server Actions from Client Components

```tsx
// app/components/delete-button.tsx
'use client'

import { deletePost } from '@/app/actions'
import { useTransition } from 'react'

export function DeleteButton({ postId }: { postId: string }) {
  const [isPending, startTransition] = useTransition()

  return (
    <button
      onClick={() => startTransition(() => deletePost(postId))}
      disabled={isPending}
    >
      {isPending ? 'Deleting...' : 'Delete'}
    </button>
  )
}
```

## Revalidation

```tsx
'use server'

import { revalidatePath } from 'next/cache'
import { revalidateTag } from 'next/cache'

export async function updatePost(id: string, data: FormData) {
  await db.post.update({ where: { id }, data: { title: data.get('title') as string } })

  // Revalidate a specific path
  revalidatePath('/blog')
  revalidatePath(`/blog/${id}`)

  // Or revalidate by cache tag
  revalidateTag('posts')
}
```

## Optimistic Updates

```tsx
'use client'

import { useOptimistic } from 'react'
import { addTodo } from './actions'

export function TodoList({ todos }: { todos: Todo[] }) {
  const [optimisticTodos, addOptimisticTodo] = useOptimistic(
    todos,
    (state, newTodo: string) => [
      ...state,
      { id: 'temp', title: newTodo, completed: false },
    ]
  )

  async function handleSubmit(formData: FormData) {
    const title = formData.get('title') as string
    addOptimisticTodo(title)
    await addTodo(formData)
  }

  return (
    <>
      <form action={handleSubmit}>
        <input name="title" />
        <button type="submit">Add</button>
      </form>
      <ul>
        {optimisticTodos.map(todo => (
          <li key={todo.id}>{todo.title}</li>
        ))}
      </ul>
    </>
  )
}
```

## Error Handling

```tsx
'use server'

export async function createItem(formData: FormData) {
  try {
    const item = await db.item.create({
      data: { name: formData.get('name') as string },
    })
    revalidatePath('/items')
    return { success: true, item }
  } catch (error) {
    return { success: false, error: 'Failed to create item' }
  }
}
```

## Security

Server Actions create a public HTTP endpoint behind the scenes. Next.js:
- Encrypts action references to prevent client-side tampering
- Uses non-guessable action IDs
- Validates the `Origin` header against the `Host` header (CSRF protection)

Always validate and sanitize inputs in Server Actions — they are exposed endpoints.
